class Solution {
public:
    int longestPalindrome(string s, string t) {
        string combined = s + t;
        int n = combined.size();
        int m = s.size();
        vector<vector<int>> dp(n, vector<int>(n, 0));
        int maxLength = 0;

        for (int length = 1; length <= n; ++length) {
            for (int i = 0; i <= n - length; ++i) {
                int j = i + length - 1;
                if (length == 1) {
                    dp[i][j] = 1;
                } else if (length == 2) {
                    dp[i][j] = combined[i] == combined[j] ? 2 : 1;
                } else {
                    dp[i][j] = combined[i] == combined[j] ? 2 + dp[i + 1][j - 1] : max(dp[i + 1][j], dp[i][j - 1]);
                }
                if (i < m && j >= m && combined[i] == combined[j]) {
                    maxLength = max(maxLength, length);
                }
            }
        }
        return maxLength;
    }
};
